1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Step = { op: string; items: Item[] };
3	type Result = { premium: number };
4	type ScenarioInput = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	type ScenarioOutput = { results: Result[] };
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
17	const CURSED_SURCHARGE_PERCENT = 50;
18	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT_PERCENT = 20;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	const REPEAT_CONTRACT_DISCOUNT_PERCENT = 15;
23	const PROCESSING_FEE = 5;
24	
25	const addSurchargePercent = (amount: number, percent: number): number =>
26	  (amount * (100 + percent)) / 100;
27	
28	const applyDiscountPercent = (amount: number, percent: number): number =>
29	  (amount * (100 - percent)) / 100;
30	
31	const addSurchargeIf = (amount: number, condition: boolean, percent: number): number =>
32	  condition ? addSurchargePercent(amount, percent) : amount;
33	
34	const applyDiscountIf = (amount: number, condition: boolean, percent: number): number =>
35	  condition ? applyDiscountPercent(amount, percent) : amount;
36	
37	const itemPremium = (item: Item): number => {
38	  const base = BASE_PREMIUMS[item.type];
39	  const withCursed = addSurchargeIf(base, item.cursed, CURSED_SURCHARGE_PERCENT);
40	  return addSurchargeIf(
41	    withCursed,
42	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
43	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
44	  );
45	};
46	
47	const sumItemPremiums = (items: Item[]): number =>
48	  items.reduce((sum, item) => sum + itemPremium(item), 0);
49	
50	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFirstQuote: boolean): number => {
51	  const itemsTotal = sumItemPremiums(items);
52	  const withContractAdjustment = isFirstQuote
53	    ? addSurchargePercent(itemsTotal, FIRST_INSURANCE_SURCHARGE_PERCENT)
54	    : applyDiscountPercent(itemsTotal, REPEAT_CONTRACT_DISCOUNT_PERCENT);
55	  const withLoyalty = applyDiscountIf(
56	    withContractAdjustment,
57	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
58	    LOYALTY_DISCOUNT_PERCENT,
59	  );
60	  return withLoyalty + PROCESSING_FEE;
61	};
62	
63	export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
64	  results: input.steps.map((step, index) => ({
65	    premium: quotePremium(step.items, input.customer.yearsWithMHPCO, index === 0),
66	  })),
67	});
